VALUES
  ('police-8b7f1efc-moex-00537', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察依法行使職權，因人民特別犧牲，致其生命、身體或財產遭受損失時，人民得請求補償。該 項損失補償，應以何種方式為之？', '["回復原狀", "以金錢為之", "回復原狀為原則，金錢為例外", "法無明定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00538', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列何者非警察勤務條例有關勤務時間之規定？', '["服勤時間之分配，以勤四、息八為原則", "服勤人員每週輪休全日二次，遇有臨時事故不得停止之", "零時至六時為深夜勤，十八時至二十四時為夜勤，餘為日勤", "服勤人員每日應有連續八小時之睡眠時間，深夜勤務以不超過四小時為度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00539', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列對分駐（派出）所的說明何者錯誤？', '["未設警察分局之鄉（鎮、市、區）公所所在地得設置分駐所", "分駐（派出）所轄區內應有三個以上警察勤務區", "分駐（派出）所轄區以不跨越鄉（鎮、市、區）為原則", "分駐（派出）所轄區以不分割村里自治區域為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00540', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關治安顧慮人口查訪規定之敘述，下列何者錯誤？', '["查訪治安顧慮人口之期間，以刑執行完畢或假釋出獄後三年為限", "治安顧慮人口由戶籍地警察機關每二個月實施查訪一次", "警察實施查訪，應於日間為之。但與查訪對象約定者，不在此限", "警察實施查訪時，應穿制服或出示證件表明身分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "fe419e42d44b", "answer_pdf_sha1": "70c257965827", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00541', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'essay', '家庭暴力防治工作需要網絡合作，對被害人的保護協助也強調提供整合
性的服務，請試述整合性服務的概念以及被害人為何需要整合性服務的
理由？並以家庭暴力安全防護網為例，說明警察的角色、防治作為及警
察如何與網絡合作？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00542', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'essay', '「警力有限，民力無窮」，警察在治安交通問題有賴民眾的協助。請試述
警民合作的意義以及我國有那些警民合作的機制？並舉一例說明警察
在治安交通上如何運用民力及可以獲致的效益。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00543', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'OscarNewman是發展情境犯罪預防觀點的先驅，1970年推出「防衛空間」的觀念，藉由特殊的 建築設計，以減低犯罪行為發生的機會，下列何者符合防衛空間的規劃要素？', '["環境設計應規劃高牆阻礙，讓有企圖的犯罪者無法順利進入空間遂行犯罪", "屋主或管理者在犯罪發生當下，能夠第一時間拿取防衛器具並採取合宜措施", "不讓外人清楚的了解物理及建築結構以及相關監控設施，才能引君入甕", "建築物設計應建立與社區鄰里親密接觸的正面形象，使其不易受到侵害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00544', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關犯罪預防相關的理論敘述，下列何者錯誤？', '["Cohen 和 Felson 的日常活動理論，認為犯罪預防可從合適的標的物、有動機的犯罪者以及缺 乏監控三條件，進行犯罪預防策略制定", "Wilson和Kelling的破窗理論，認為社區應該加以進行破壞與毀損，讓犯罪者發現該社區無任 何值錢的物品可偷竊，方能達到犯罪預防的目標", "理性選擇理論認為犯罪是一種目標導向的行為，因此犯罪預防策略設計應根據犯罪者本身的風 險、需求、成本與利益之間的關係來進行設計", "犯罪型態理論強調犯罪者的居住、工作與休閒的地點範圍，犯罪者會在這三個點當中的路徑尋 找犯罪機會，不太會遠離自己所熟悉的區域"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00545', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '毒品與犯罪一直是社會所關切的議題，對於毒品犯罪的介入手段，從執法、處遇及預防缺一不可， 有關警政與毒品犯罪的關係，下列何者錯誤？', '["新興毒品的檢測不易，為了妥善利用人力，因此將目標放在降低吸食毒品的人口，相關緝毒工 作轉由檢察機關與調查局負責", "針對高風險參與犯罪活動之人的毒品施用早期介入，能有效減少犯罪發生，達到犯罪預防的目的", "境外合作與邊境防堵、溯源斷根來減少毒品供給，雖然能夠降低犯罪的發生，但也會出現犯罪 移轉的現象", "為掌握最新毒品情資，可規劃建置「毒品查緝情資整合分析資料庫」，整合毒品相關資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00546', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '跨境詐欺犯罪因全球化而崛起，近來更因為新冠肺炎的肆虐而愈趨嚴重，犯罪儼然不再是單純的 地區問題，跨境警察合作組織將成為未來跨境犯罪的重要關鍵。針對跨境詐欺犯罪的情境犯罪預 防應有的作為，下列何者錯誤？', '["放寬二類電信審核與查核，減少匿名性方式來增加犯罪風險", "增加ATM的巡邏頻率，強化金融機構攔阻作為，可增加犯罪的阻力", "打擊車手集團，使車手集團經營需耗費大量成本，相對減少犯罪酬賞", "透過法治宣導與法律來激發潛在犯罪者的良心，移除犯罪藉口"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
